import pytest

class HookManager:
    def __init__(self):
        self.hooks = {}

    def deregister_hook(self, event, hook):
        """Deregister a previously registered hook.
        Returns True if the hook existed, False if not.
        """
        try:
            self.hooks[event].remove(hook)
            return True
        except ValueError:
            return False
        except KeyError:
            return False

# Test cases
def test_deregister_existing_hook():
    manager = HookManager()
    manager.hooks = {'event1': ['hook1', 'hook2']}
    assert manager.deregister_hook('event1', 'hook1') is True
    assert manager.hooks['event1'] == ['hook2']

def test_deregister_non_existing_hook():
    manager = HookManager()
    manager.hooks = {'event1': ['hook1', 'hook2']}
    assert manager.deregister_hook('event1', 'hook3') is False
    assert manager.hooks['event1'] == ['hook1', 'hook2']

def test_deregister_hook_from_empty_event():
    manager = HookManager()
    manager.hooks = {'event1': []}
    assert manager.deregister_hook('event1', 'hook1') is False

def test_deregister_hook_from_non_existing_event():
    manager = HookManager()
    manager.hooks = {'event1': ['hook1']}
    assert manager.deregister_hook('event2', 'hook1') is False

def test_deregister_last_hook():
    manager = HookManager()
    manager.hooks = {'event1': ['hook1']}
    assert manager.deregister_hook('event1', 'hook1') is True
    assert manager.hooks['event1'] == []

def test_deregister_hook_with_multiple_hooks():
    manager = HookManager()
    manager.hooks = {'event1': ['hook1', 'hook2', 'hook3']}
    assert manager.deregister_hook('event1', 'hook2') is True
    assert manager.hooks['event1'] == ['hook1', 'hook3']

def test_deregister_hook_with_different_data_types():
    manager = HookManager()
    manager.hooks = {'event1': [1, 2, 3]}
    assert manager.deregister_hook('event1', 2) is True
    assert manager.hooks['event1'] == [1, 3]

def test_deregister_hook_with_non_hashable_type():
    manager = HookManager()
    manager.hooks = {'event1': [{}, {}]}
    assert manager.deregister_hook('event1', {}) is False  # This will always return False since {} is not the same instance

# Run the tests
if __name__ == "__main__":
    pytest.main()

