import pytest

_marker = object()  # This is the marker used in the function

def first(iterable, default=_marker):
    for item in iterable:
        return item
    if default is _marker:
        raise ValueError(
            'first() was called on an empty iterable, '
            'and no default value was provided.'
        )
    return default

def test_first_with_non_empty_list():
    assert first([0, 1, 2, 3]) == 0

def test_first_with_non_empty_tuple():
    assert first((10, 20, 30)) == 10

def test_first_with_non_empty_string():
    assert first("hello") == 'h'

def test_first_with_generator():
    assert first(iter(range(5))) == 0

def test_first_with_empty_list_and_default():
    assert first([], 'some default') == 'some default'

def test_first_with_empty_tuple_and_default():
    assert first((), 42) == 42

def test_first_with_empty_iterable_no_default():
    with pytest.raises(ValueError, match='first() was called on an empty iterable'):
        first([])

def test_first_with_single_element_list():
    assert first([42]) == 42

def test_first_with_single_element_generator():
    assert first(iter([99])) == 99

def test_first_with_large_iterable():
    large_iterable = range(1000000)
    assert first(large_iterable) == 0

def test_first_with_none_as_first_item():
    assert first([None, 1, 2]) == None

def test_first_with_non_iterable():
    with pytest.raises(TypeError):
        first(123)  # Passing an integer instead of an iterable

def test_first_with_empty_iterable_and_no_default():
    with pytest.raises(ValueError):
        first([])

# Run the tests
if __name__ == "__main__":
    pytest.main()

