import pytest
from random import shuffle
from operator import itemgetter

# Assuming the function random_derangement is defined here

def random_derangement(iterable):
    """Return a random derangement of elements in the iterable."""
    seq = tuple(iterable)
    if len(seq) < 2:
        if len(seq) == 0:
            return ()
        raise IndexError('No derangements to choose from')
    perm = list(range(len(seq)))
    start = tuple(perm)
    while True:
        shuffle(perm)
        if not any(map(is_, start, perm)):
            return itemgetter(*perm)(seq)

def test_empty_iterable():
    assert random_derangement([]) == ()

def test_single_element_iterable():
    with pytest.raises(IndexError):
        random_derangement([1])

def test_two_elements():
    result = random_derangement([1, 2])
    assert result in [(2, 1)]

def test_three_elements():
    result = random_derangement([1, 2, 3])
    assert result in [(2, 3, 1), (3, 1, 2), (2, 1, 3), (1, 3, 2)]

